module top_module(
  input CLK,
  input EN,
  input TE,
  input reset,
  output ENCLK
);reg unused_ENCLK_reg;

  always @(posedge CLK, posedge reset) begin
    if (reset) begin
      unused_ENCLK_reg <= 1'b0;
    end else if (EN && TE) begin
      unused_ENCLK_reg <= ~unused_ENCLK_reg;
    end
  end

  assign ENCLK = unused_ENCLK_reg;

endmodule
